import{_ as a,c as e,o as r,a1 as t}from"./chunks/framework.9hXSu8bi.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/帮助文档/开始使用/基本概念.md","filePath":"zh/帮助文档/开始使用/基本概念.md"}'),o={name:"zh/帮助文档/开始使用/基本概念.md"},h=t('<h2 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to &quot;基本概念&quot;">​</a></h2><blockquote><p>本节介绍系统使用过程中出现的核心名词，帮助用户快速理解平台功能和术语含义。</p></blockquote><h3 id="_1-项目" tabindex="-1">1. 项目 <a class="header-anchor" href="#_1-项目" aria-label="Permalink to &quot;1. 项目&quot;">​</a></h3><p>项目是监测任务的最高层级组织单元，通常对应一个物理区域（如某边坡、矿山或大坝）。一个项目可包含多个子项目，便于分区域、分设备管理。项目支持数据联网、第三方传感器接入、地形管理等功能，基本信息包括项目名称、地址、经纬度、创建时间等。</p><h3 id="_2-子项目" tabindex="-1">2. 子项目 <a class="header-anchor" href="#_2-子项目" aria-label="Permalink to &quot;2. 子项目&quot;">​</a></h3><p>子项目隶属于某个项目，代表更具体的监测对象或分区（如某边坡的不同断面、某矿山的多个台阶）。每个子项目可关联独立的地形数据、雷达设备、预警策略，并生成独立的监测曲线和报告。子项目基本信息包括：状态（在线/离线），当前步骤（如待切片、已融合等），最新数据时间等。</p><h3 id="_3-结项" tabindex="-1">3. 结项 <a class="header-anchor" href="#_3-结项" aria-label="Permalink to &quot;3. 结项&quot;">​</a></h3><p>结项表示项目或子项目已结束监测任务，进入归档状态。结项后的子项目默认不可编辑，但历史数据仍可查看。如需重新启用，可联系管理员调整状态。</p><h3 id="_4-用户" tabindex="-1">4. 用户 <a class="header-anchor" href="#_4-用户" aria-label="Permalink to &quot;4. 用户&quot;">​</a></h3><p>用户是系统的操作者，每个用户拥有独立的账号、密码、姓名、手机号、邮箱等信息。用户账号状态分为“正常”和“冻结”。通过分配的角色获得相应操作权限，并可配置设备套餐。</p><h3 id="_5-角色" tabindex="-1">5. 角色 <a class="header-anchor" href="#_5-角色" aria-label="Permalink to &quot;5. 角色&quot;">​</a></h3><p>角色是权限的集合，用于控制用户对系统功能的访问范围。角色性质分为“公共”和“私有”。系统内置管理员、普通用户等角色，也支持自定义角色，并可分别配置管理页面、三维页面的授权。</p><h3 id="_6-地形数据" tabindex="-1">6. 地形数据 <a class="header-anchor" href="#_6-地形数据" aria-label="Permalink to &quot;6. 地形数据&quot;">​</a></h3><p>地形数据是指描述地表形态的数字化文件（如TIFF、OSGB、SHP等）。平台支持上传地形数据，并与雷达数据融合，生成三维地形场景，为监测提供真实的地理背景。</p><h3 id="_7-雷达数据" tabindex="-1">7. 雷达数据 <a class="header-anchor" href="#_7-雷达数据" aria-label="Permalink to &quot;7. 雷达数据&quot;">​</a></h3><p>雷达数据是通过雷达设备采集的原始形变信息，通常以diff格式上传。平台对雷达数据进行处理，生成监测点的位移曲线、形变图等。在子项目-雷达数据中可查看历史雷达在线率。</p><h3 id="_8-地形融合" tabindex="-1">8. 地形融合 <a class="header-anchor" href="#_8-地形融合" aria-label="Permalink to &quot;8. 地形融合&quot;">​</a></h3><p>地形融合是将地形数据与雷达数据坐标对齐、叠加的过程，使监测结果精确显示在地形模型上。融合前需输入雷达坐标信息，确保空间位置匹配。</p><h3 id="_9-监测点" tabindex="-1">9. 监测点 <a class="header-anchor" href="#_9-监测点" aria-label="Permalink to &quot;9. 监测点&quot;">​</a></h3><p>监测点是用户在地图上手动标记的单个位置，用于观察该点的形变变化。平台会实时绘制该点的形变曲线，支持历史数据回溯。</p><h3 id="_10-监测面" tabindex="-1">10. 监测面 <a class="header-anchor" href="#_10-监测面" aria-label="Permalink to &quot;10. 监测面&quot;">​</a></h3><p>监测面是用户在地图上绘制的多边形区域，用于分析该区域内整体的形变趋势。平台可生成监测面的平均形变曲线、形变分布图等。</p><h3 id="_11-运行参数" tabindex="-1">11. 运行参数 <a class="header-anchor" href="#_11-运行参数" aria-label="Permalink to &quot;11. 运行参数&quot;">​</a></h3><p>运行参数指雷达设备的运行配置，如起始角度、观测近距、起始数据时间等，用户可在子项目中查看这些参数。</p><h3 id="_12-坐标系" tabindex="-1">12. 坐标系 <a class="header-anchor" href="#_12-坐标系" aria-label="Permalink to &quot;12. 坐标系&quot;">​</a></h3><p>坐标系是定义地理空间位置的参考框架。平台支持CGCS2000坐标系，用户在上传地形或雷达数据时需确保坐标系一致。</p><h3 id="_13-epsg" tabindex="-1">13. EPSG <a class="header-anchor" href="#_13-epsg" aria-label="Permalink to &quot;13. EPSG&quot;">​</a></h3><p>EPSG（European Petroleum Survey Group）是空间参考系统的国际代码，用于唯一标识坐标系。</p><blockquote><p>（注：以上概念将随系统版本迭代不断丰富，具体以实际界面为准。）</p></blockquote>',29),i=[h];function l(n,_,d,c,s,p){return r(),e("div",null,i)}const q=a(o,[["render",l]]);export{b as __pageData,q as default};
